namespace sv_e8cb309df0a642a6837cfe25aa96f9be.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_e8cb309df0a642a6837cfe25aa96f9be.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_e8cb309df0a642a6837cfe25aa96f9be.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          IsMoving="movingTaskId == task.Id"
                          OnMoveLeft="() => HandleMoveLeft(task.Id)"
                          OnMoveRight="() => HandleMoveRight(task.Id)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm OnSave="HandleSave"
                             OnCancel="() => showAddForm = false"
                             IsSaving="isSaving" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showAddForm;
    private bool isSaving;
    private int? movingTaskId;

    private async Task HandleMoveLeft(int taskId)
    {
        if (LeftStatus is null) return;
        movingTaskId = taskId;
        await OnTaskMoved.InvokeAsync((taskId, LeftStatus));
        movingTaskId = null;
    }

    private async Task HandleMoveRight(int taskId)
    {
        if (RightStatus is null) return;
        movingTaskId = taskId;
        await OnTaskMoved.InvokeAsync((taskId, RightStatus));
        movingTaskId = null;
    }

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        isSaving = true;
        await OnTaskCreated.InvokeAsync(data);
        isSaving = false;
        showAddForm = false;
    }
}

@page "/board"
@using sv_e8cb309df0a642a6837cfe25aa96f9be.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="allTasks.Count"
                     TodoCount="TodoTasks.Count"
                     InProgressCount="InProgressTasks.Count"
                     DoneCount="DoneTasks.Count"
                     OverdueCount="OverdueCount" />

    <SearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Status="To Do"
                      Tasks="FilteredTodoTasks"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      LeftStatus="@null"
                      RightStatus="In Progress"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, \"To Do\")" />

        <KanbanColumn ColumnName="In Progress"
                      Status="In Progress"
                      Tasks="FilteredInProgressTasks"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      LeftStatus="To Do"
                      RightStatus="Done"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, \"In Progress\")" />

        <KanbanColumn ColumnName="Done"
                      Status="Done"
                      Tasks="FilteredDoneTasks"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      LeftStatus="In Progress"
                      RightStatus="@null"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered lists (for summary stats)
    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private int OverdueCount => allTasks.Count(t => t.DueDate.Date < DateTime.Today);

    // Filtered lists (for display in columns)
    private List<TaskItem> FilteredTodoTasks => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgressTasks => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDoneTasks => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText)) return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.First(t => t.Id == args.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = args.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // The service creates with a default status; ensure it matches the column
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

