@using sv_e8cb309df0a642a6837cfe25aa96f9be.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="allTasks.Count"
                     TodoCount="TodoTasks.Count"
                     InProgressCount="InProgressTasks.Count"
                     DoneCount="DoneTasks.Count"
                     OverdueCount="OverdueCount" />

    <SearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Status="To Do"
                      Tasks="FilteredTodoTasks"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      LeftStatus="@null"
                      RightStatus="In Progress"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, \"To Do\")" />

        <KanbanColumn ColumnName="In Progress"
                      Status="In Progress"
                      Tasks="FilteredInProgressTasks"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      LeftStatus="To Do"
                      RightStatus="Done"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, \"In Progress\")" />

        <KanbanColumn ColumnName="Done"
                      Status="Done"
                      Tasks="FilteredDoneTasks"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      LeftStatus="In Progress"
                      RightStatus="@null"
                      OnTaskMoved="HandleTaskMoved"
                      OnTaskCreated="args => HandleTaskCreated(args, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered lists (for summary stats)
    private List<TaskItem> TodoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private int OverdueCount => allTasks.Count(t => t.DueDate.Date < DateTime.Today);

    // Filtered lists (for display in columns)
    private List<TaskItem> FilteredTodoTasks => ApplySearch(TodoTasks);
    private List<TaskItem> FilteredInProgressTasks => ApplySearch(InProgressTasks);
    private List<TaskItem> FilteredDoneTasks => ApplySearch(DoneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText)) return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.First(t => t.Id == args.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = args.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            // The service creates with a default status; ensure it matches the column
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}
"}

